#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

void generate_combinations(int *arr, int n, int k, int start, int *current, int index, int *combinations, int *count) {
    if (index == k) {
        for (int i = 0; i < k; i++) {
            combinations[(*count) * k + i] = current[i];
        }
        (*count)++;
        return;
    }
    for (int i = start; i < n; i++) {
        current[index] = arr[i];
        generate_combinations(arr, n, k, i + 1, current, index + 1, combinations, count);
    }
}

int main() {
    int n, l, r, x;
    scanf("%d %d %d %d", &n, &l, &r, &x);
    int *li = malloc(n * sizeof(int));
    for (int i = 0; i < n; i++) {
        scanf("%d", &li[i]);
    }

    int total_combinations = 0;
    for (int k = 2; k <= n; k++) {
        int max_comb = 1;
        for (int i = n; i > n - k; i--) max_comb *= i;
        for (int i = k; i > 1; i--) max_comb /= i;
        total_combinations += max_comb;
    }

    int *combinations = malloc(total_combinations * n * sizeof(int));
    int *current = malloc(n * sizeof(int));
    int count = 0;
    for (int k = 2; k <= n; k++) {
        generate_combinations(li, n, k, 0, current, 0, combinations, &count);
    }

    int ans = 0;
    for (int i = 0; i < count; i++) {
        int k = 2;
        while (i > 0 && combinations[i * n] == combinations[(i - 1) * n]) {
            k++;
            i--;
        }
        int *a = malloc(k * sizeof(int));
        for (int j = 0; j < k; j++) {
            a[j] = combinations[i * n + j];
        }
        qsort(a, k, sizeof(int), compare);
        int sum = 0;
        for (int j = 0; j < k; j++) {
            sum += a[j];
        }
        if (a[k - 1] - a[0] >= x && sum >= l && sum <= r) {
            ans++;
        }
        free(a);
    }

    printf("%d\n", ans);
    free(li);
    free(combinations);
    free(current);
    return 0;
}
